var getOrder = function(tasks) {
    const n = tasks.length;
    const idx = [...Array(n).keys()].sort((a, b) => tasks[a][0] - tasks[b][0]);
    // min-heap of [processing, index]
    const heap = [];
    const less = (a, b) => a[0] !== b[0] ? a[0] < b[0] : a[1] < b[1];
    const push = (x) => {
        heap.push(x);
        let c = heap.length - 1;
        while (c > 0) {
            const p = (c - 1) >> 1;
            if (less(heap[c], heap[p])) { [heap[c], heap[p]] = [heap[p], heap[c]]; c = p; }
            else break;
        }
    };
    const pop = () => {
        const top = heap[0];
        const last = heap.pop();
        if (heap.length) {
            heap[0] = last;
            let c = 0;
            const sz = heap.length;
            while (true) {
                let s = c, l = 2 * c + 1, r = 2 * c + 2;
                if (l < sz && less(heap[l], heap[s])) s = l;
                if (r < sz && less(heap[r], heap[s])) s = r;
                if (s === c) break;
                [heap[c], heap[s]] = [heap[s], heap[c]];
                c = s;
            }
        }
        return top;
    };
    const res = [];
    let time = 0, ptr = 0;
    while (res.length < n) {
        while (ptr < n && tasks[idx[ptr]][0] <= time) {
            const i = idx[ptr];
            push([tasks[i][1], i]);
            ptr++;
        }
        if (heap.length === 0) { time = tasks[idx[ptr]][0]; continue; }
        const [proc, i] = pop();
        res.push(i);
        time += proc;
    }
    return res;
};
